 1	import * as React from 'react';
 2	import { PrometheusUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-utilization-item';
 3	import { DeploymentModel } from '@odf/shared/models';
 4	import {
 5	  DeploymentQueries,
 6	  getUtilizationQueries,
 7	} from '@odf/shared/queries/deployment';
 8	import { getName } from '@odf/shared/selectors';
 9	import { DeploymentKind } from '@odf/shared/types';
10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
11	import { humanizeCpuCores, humanizeBinaryBytes } from '@odf/shared/utils';
12	import { UtilizationBody } from '@openshift-console/dynamic-plugin-sdk-internal';
13	import { ByteDataTypes } from '@openshift-console/dynamic-plugin-sdk-internal/lib/api/internal-types';
14	import { Card, CardHeader, CardTitle } from '@patternfly/react-core';
15	import '../node/node-observe.scss';
16	
17	type NodeObserveProps = {
18	  resource: DeploymentKind;
19	  odfNamespace?: string;
20	};
21	
22	export const DeploymentObserve: React.FC<NodeObserveProps> = ({
23	  resource: deployment,
24	  odfNamespace,
25	}) => {
26	  const { t } = useCustomTranslation();
27	
28	  const name = getName(deployment);
29	
30	  const utilizationQueries = getUtilizationQueries(
31	    odfNamespace,
32	    name,
33	    DeploymentModel.kind.toLowerCase()
34	  );
35	
36	  return (
37	    <Card className="node-observe-tab" data-test-id="node-observe-tab">
38	      <CardHeader>
39	        <CardTitle>{t('Metrics')}</CardTitle>
40	      </CardHeader>
41	      <UtilizationBody>
42	        <PrometheusUtilizationItem
43	          title={t('CPU usage')}
44	          humanizeValue={humanizeCpuCores}
45	          utilizationQuery={utilizationQueries[DeploymentQueries.CPU_USAGE]}
46	        />
47	        <PrometheusUtilizationItem
48	          title={t('Memory')}
49	          humanizeValue={humanizeBinaryBytes}
50	          utilizationQuery={utilizationQueries[DeploymentQueries.MEMORY_USAGE]}
51	          byteDataType={ByteDataTypes.BinaryBytes}
52	        />
53	        <PrometheusUtilizationItem
54	          title={t('Receive bandwidth')}
55	          humanizeValue={humanizeBinaryBytes}
56	          utilizationQuery={
57	            utilizationQueries[DeploymentQueries.RECEIVE_BANDWIDTH]
58	          }
59	          byteDataType={ByteDataTypes.BinaryBytes}
60	        />
61	      </UtilizationBody>
62	    </Card>
63	  );
64	};

